@Override
public boolean equals(Object o) {
    if (this == o) return true;
    if (!(o instanceof Account)) return false;
    Account account = (Account) o;
    return accountNumber != null && accountNumber.equals(account.accountNumber);
}

@Override
public int hashCode() {
    return getClass().hashCode();
}


@Repository
public interface AccountRepository extends JpaRepository<Account, Long> {

    // Query methods derived from method name
    Optional<Account> findByAccountNumber(String accountNumber);

    List<Account> findByUserId(Long userId);

    boolean existsByAccountNumber(String accountNumber);

    // Custom query with @Query
    @Query("SELECT a FROM Account a WHERE a.user.id = :userId AND a.accountType = :type")
    List<Account> findUserAccountsByType(@Param("userId") Long userId, 
                                         @Param("type") AccountType type);

    // Native query when needed
    @Query(value = "SELECT * FROM accounts WHERE balance > :minBalance", nativeQuery = true)
    List<Account> findAccountsWithMinBalance(@Param("minBalance") BigDecimal minBalance);

    // Projection for specific fields
    @Query("SELECT new com.abcbank.dto.AccountSummary(a.accountNumber, a.balance) " +
           "FROM Account a WHERE a.user.id = :userId")
    List<AccountSummary> findAccountSummariesByUserId(@Param("userId") Long userId);
}


