@Query("SELECT a FROM Account a WHERE a.id = :id")
Optional<Account> findByIdWithDetails(@Param("id") Long id);


@Service
@Transactional
@Slf4j
public class TransferService {

    private final AccountRepository accountRepository;
    private final TransactionRepository transactionRepository;

    @Transactional(readOnly = true)
    public List<AccountDTO> getUserAccounts(Long userId) {
        log.debug("Fetching accounts for user: {}", userId);
        return accountRepository.findByUserId(userId)
            .stream()
            .map(this::convertToDTO)
            .collect(Collectors.toList());
    }

    @Transactional(rollbackFor = Exception.class)
    public TransferResponse executeTransfer(TransferRequest request) {
        log.info("Executing transfer: {} -> {}, amount: {}", 
            request.getFromAccount(), request.getToAccount(), request.getAmount());

        // Validate and execute transfer
        Account fromAccount = accountRepository
            .findByAccountNumber(request.getFromAccount())
            .orElseThrow(() -> new AccountNotFoundException("Source account not found"));

        Account toAccount = accountRepository
            .findByAccountNumber(request.getToAccount())
            .orElseThrow(() -> new AccountNotFoundException("Destination account not found"));

        validateTransfer(fromAccount, request.getAmount());

        // Perform transfer
        fromAccount.setBalance(fromAccount.getBalance().subtract(request.getAmount()));
        toAccount.setBalance(toAccount.getBalance().add(request.getAmount()));

        // Create transaction records
        Transaction debit = createTransaction(fromAccount, request.getAmount().negate(), "DEBIT");
        Transaction credit = createTransaction(toAccount, request.getAmount(), "CREDIT");

        accountRepository.saveAll(List.of(fromAccount, toAccount));
        transactionRepository.saveAll(List.of(debit, credit));

        log.info("Transfer completed successfully");
        return new TransferResponse(true, "Transfer successful");
    }

    private void validateTransfer(Account account, BigDecimal amount) {
        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            throw new InvalidAmountException("Amount must be positive");
        }
        if (account.getBalance().compareTo(amount) < 0) {
            throw new InsufficientFundsException("Insufficient balance");
        }
    }
}


// DTO classes
@Data
@Builder
public class AccountDTO {
    private Long id;
    private String accountNumber;
    private String accountType;
    private BigDecimal balance;
    private String ownerName;
}

// Conversion in service
private AccountDTO convertToDTO(Account account) {
    return AccountDTO.builder()
        .id(account.getId())
        .accountNumber(account.getAccountNumber())
        .accountType(account.getAccountType().name())
        .balance(account.getBalance())
        .ownerName(account.getUser().getFullName())
        .build();
}

// Or use MapStruct for complex mappings
@Mapper(componentModel = "spring")
public interface AccountMapper {
    AccountDTO toDTO(Account account);
    List<AccountDTO> toDTOList(List<Account> accounts);
}


@Service
@Slf4j
public class AccountService {

    public AccountDTO getAccount(Long id) {
        log.debug("Fetching account with id: {}", id); // DEBUG for detailed info

        Account account = accountRepository.findById(id)
            .orElseThrow(() -> {
                log.warn("Account not found: {}", id); // WARN for expected errors
                return new AccountNotFoundException("Account not found");
            });

        log.info("Account retrieved: {}", account.getAccountNumber()); // INFO for important events
        return convertToDTO(account);
    }

    public void processTransaction(Transaction txn) {
        try {
            // Process transaction
            log.info("Transaction processed: {}", txn.getId());
        } catch (Exception e) {
            log.error("Failed to process transaction: {}", txn.getId(), e); // ERROR with exception
            throw e;
        }
    }
}


@RestController
@RequestMapping("/api/accounts")
@Slf4j
@RequiredArgsConstructor
public class AccountController {

    private final AccountService accountService;

    @GetMapping
    public ResponseEntity<List<AccountDTO>> getUserAccounts(Principal principal) {
        log.info("Fetching accounts for user: {}", principal.getName());
        List<AccountDTO> accounts = accountService.getAccountsByUsername(principal.getName());
        return ResponseEntity.ok(accounts);
    }

    @GetMapping("/{id}")
    public ResponseEntity<AccountDTO> getAccount(
            @PathVariable Long id,
            Principal principal) {
        log.info("Fetching account {} for user: {}", id, principal.getName());
        AccountDTO account = accountService.getAccount(id, principal.getName());
        return ResponseEntity.ok(account);
    }

    @PostMapping
    public ResponseEntity<AccountDTO> createAccount(
            @Valid @RequestBody CreateAccountRequest request,
            Principal principal) {
        log.info("Creating account for user: {}", principal.getName());
        AccountDTO account = accountService.createAccount(request, principal.getName());
        return ResponseEntity
            .created(URI.create("/api/accounts/" + account.getId()))
            .body(account);
    }

    @PutMapping("/{id}")
    public ResponseEntity<AccountDTO> updateAccount(
            @PathVariable Long id,
            @Valid @RequestBody UpdateAccountRequest request,
            Principal principal) {
        log.info("Updating account {} for user: {}", id, principal.getName());
        AccountDTO account = accountService.updateAccount(id, request, principal.getName());
        return ResponseEntity.ok(account);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteAccount(
            @PathVariable Long id,
            Principal principal) {
        log.info("Deleting account {} for user: {}", id, principal.getName());
        accountService.deleteAccount(id, principal.getName());
        return ResponseEntity.noContent().build();
    }
}


@Data
public class TransferRequest {

    @NotBlank(message = "Source account is required")
    @Pattern(regexp = "\\d{4,20}", message = "Invalid account number format")
    private String fromAccount;

    @NotBlank(message = "Destination account is required")
    @Pattern(regexp = "\\d{4,20}", message = "Invalid account number format")
    private String toAccount;

    @NotNull(message = "Amount is required")
    @DecimalMin(value = "0.01", message = "Amount must be positive")
    @DecimalMax(value = "1000000.00", message = "Amount exceeds maximum limit")
    private BigDecimal amount;

    @Size(max = 200, message = "Description too long")
    private String description;
}

// In controller
@PostMapping("/transfers")
public ResponseEntity<TransferResponse> transfer(
        @Valid @RequestBody TransferRequest request,
        Principal principal) {
    // Validation happens automatically
    TransferResponse response = transferService.executeTransfer(request, principal.getName());
    return ResponseEntity.ok(response);
}


@ControllerAdvice
@Slf4j
public class GlobalExceptionHandler {

    @ExceptionHandler(AccountNotFoundException.class)
    public ResponseEntity<ErrorResponse> handleAccountNotFound(AccountNotFoundException ex) {
        log.warn("Account not found: {}", ex.getMessage());
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.NOT_FOUND.value())
            .error("Not Found")
            .message(ex.getMessage())
            .build();
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(InsufficientFundsException.class)
    public ResponseEntity<ErrorResponse> handleInsufficientFunds(InsufficientFundsException ex) {
        log.warn("Insufficient funds: {}", ex.getMessage());
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.BAD_REQUEST.value())
            .error("Bad Request")
            .message(ex.getMessage())
            .build();
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ErrorResponse> handleValidationErrors(MethodArgumentNotValidException ex) {
        log.warn("Validation error: {}", ex.getMessage());
        Map<String, String> errors = new HashMap<>();
        ex.getBindingResult().getFieldErrors().forEach(error ->
            errors.put(error.getField(), error.getDefaultMessage())
        );
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.BAD_REQUEST.value())
            .error("Validation Failed")
            .message("Invalid input")
            .validationErrors(errors)
            .build();
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleGenericException(Exception ex) {
        log.error("Unexpected error", ex);
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.INTERNAL_SERVER_ERROR.value())
            .error("Internal Server Error")
            .message("An unexpected error occurred")
            .build();
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);
    }
}

@Data
@Builder
public class ErrorResponse {
    private LocalDateTime timestamp;
    private int status;
    private String error;
    private String message;
    private Map<String, String> validationErrors;
}


@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf
                .ignoringRequestMatchers("/api/**") // Disable CSRF for REST APIs
            )
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/login", "/css/**", "/js/**", "/images/**").permitAll()
                .requestMatchers("/actuator/health", "/actuator/info").permitAll()
                .requestMatchers("/api/auth/**").permitAll()
                .requestMatchers("/api/admin/**").hasRole("ADMIN")
                .anyRequest().authenticated()
            )
            .formLogin(form -> form
                .loginPage("/login")
                .defaultSuccessUrl("/accounts", true)
                .failureUrl("/login?error=true")
                .permitAll()
            )
            .logout(logout -> logout
                .logoutUrl("/logout")
                .logoutSuccessUrl("/login?logout=true")
                .invalidateHttpSession(true)
                .deleteCookies("JSESSIONID")
                .permitAll()
            )
            .sessionManagement(session -> session
                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
                .maximumSessions(1)
                .maxSessionsPreventsLogin(false)
            );

        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder(12); // Strength 12
    }

    @Bean
    public AuthenticationManager authenticationManager(
            AuthenticationConfiguration authConfig) throws Exception {
        return authConfig.getAuthenticationManager();
    }
}

@Service
@RequiredArgsConstructor
public class UserDetailsServiceImpl implements UserDetailsService {

    private final UserRepository userRepository;

    @Override
    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
        User user = userRepository.findByUsername(username)
            .orElseThrow(() -> new UsernameNotFoundException("User not found: " + username));

        return org.springframework.security.core.userdetails.User.builder()
            .username(user.getUsername())
            .password(user.getPassword())
            .roles(user.getRole())
            .accountLocked(!user.isActive())
            .build();
    }
}


@Service
@RequiredArgsConstructor
public class UserService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;

    public User createUser(CreateUserRequest request) {
        // Hash password before saving
        String hashedPassword = passwordEncoder.encode(request.getPassword());

        User user = User.builder()
            .username(request.getUsername())
            .password(hashedPassword)
            .email(request.getEmail())
            .fullName(request.getFullName())
            .role("USER")
            .active(true)
            .build();

        return userRepository.save(user);
    }

    public boolean validatePassword(String rawPassword, String encodedPassword) {
        return passwordEncoder.matches(rawPassword, encodedPassword);
    }
}

