@ExtendWith(MockitoExtension.class)
class TransferServiceTest {

    @Mock
    private AccountRepository accountRepository;

    @Mock
    private TransactionRepository transactionRepository;

    @InjectMocks
    private TransferService transferService;

    @Test
    void executeTransfer_Success() {
        // Given
        Account fromAccount = Account.builder()
            .accountNumber("1001")
            .balance(new BigDecimal("1000.00"))
            .build();

        Account toAccount = Account.builder()
            .accountNumber("2001")
            .balance(new BigDecimal("500.00"))
            .build();

        TransferRequest request = TransferRequest.builder()
            .fromAccount("1001")
            .toAccount("2001")
            .amount(new BigDecimal("100.00"))
            .build();

        when(accountRepository.findByAccountNumber("1001"))
            .thenReturn(Optional.of(fromAccount));
        when(accountRepository.findByAccountNumber("2001"))
            .thenReturn(Optional.of(toAccount));

        // When
        TransferResponse response = transferService.executeTransfer(request);

        // Then
        assertThat(response.isSuccess()).isTrue();
        assertThat(fromAccount.getBalance()).isEqualByComparingTo("900.00");
        assertThat(toAccount.getBalance()).isEqualByComparingTo("600.00");

        verify(accountRepository).saveAll(anyList());
        verify(transactionRepository).saveAll(anyList());
    }

    @Test
    void executeTransfer_InsufficientFunds_ThrowsException() {
        // Given
        Account fromAccount = Account.builder()
            .accountNumber("1001")
            .balance(new BigDecimal("50.00"))
            .build();

        TransferRequest request = TransferRequest.builder()
            .fromAccount("1001")
            .toAccount("2001")
            .amount(new BigDecimal("100.00"))
            .build();

        when(accountRepository.findByAccountNumber("1001"))
            .thenReturn(Optional.of(fromAccount));

        // When/Then
        assertThatThrownBy(() -> transferService.executeTransfer(request))
            .isInstanceOf(InsufficientFundsException.class)
            .hasMessageContaining("Insufficient balance");
    }
}


@SpringBootTest
@AutoConfigureMockMvc
@Transactional
class AccountControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Test
    @WithMockUser(username = "john.doe", roles = "USER")
    void getUserAccounts_ReturnsAccounts() throws Exception {
        mockMvc.perform(get("/api/accounts"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$").isArray())
            .andExpect(jsonPath("$[0].accountNumber").exists())
            .andExpect(jsonPath("$[0].balance").exists());
    }

    @Test
    @WithMockUser(username = "john.doe", roles = "USER")
    void createTransfer_ValidRequest_ReturnsSuccess() throws Exception {
        TransferRequest request = TransferRequest.builder()
            .fromAccount("1001")
            .toAccount("2001")
            .amount(new BigDecimal("100.00"))
            .build();

        mockMvc.perform(post("/api/transfers")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.success").value(true));
    }
}
